using Microsoft.EntityFrameworkCore;
class BlogContext : DbContext
{
    public DbSet<Blog> Blogs => Set<Blog>();
    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        modelBuilder.Entity<Blog>(b =>
        {
            // Breaking change 1: Discriminator property renamed from "Discriminator" to "$type".
            // Keep old name so existing documents and raw SQL queries still work.
            b.HasDiscriminator<string>("Discriminator");

            // Breaking change 2: Key property now maps directly to Cosmos "id".
            // Existing documents use the old "Blog|{key}" synthesized format.
            b.Property(e => e.Id)
                .HasConversion(
                    v => "Blog|" + v,
                    v => v.StartsWith("Blog|") ? v.Substring(5) : v);

            // Breaking change 3: HasIndex now throws for Cosmos provider.
            // Removed — Cosmos manages indexing at the container level.
        });
    }
}
class Blog { public string Id { get; set; } public string Name { get; set; } }

